#include<bits/stdc++.h>
using namespace std;
map<string,int>m;
int main()
{
	int t;
	cin>>t;
	while(t--){
		int n;
		cin>>n;
		if(n==1){
			string s;
			cin>>s;
			int score=0;
			cin>>score;
			m[s]=score;
			cout<<"OK"<<endl;
		}else if(n==2){
			string s;
			cin>>s;
			if(m.count(s))cout<<m[s]<<endl;
			else cout<<"Not found"<<endl;
		}else if(n==3){
			string s;
			cin>>s;
			if(m.count(s)){
				m.erase(s);
				cout<<"Deleted successfully"<<endl;
			}else{
				cout<<"Not found"<<endl;
			}

		}else{
			cout<<m.size()<<endl;
		}
	}
 }
